import{_ as t,o as r,c as s,a2 as o}from"./chunks/framework.BbQrW5_t.js";const A="/my-knowledge/assets/circle-case01.B6SRKcY2.png",C="/my-knowledge/assets/circle-case02.D_AtkklD.png",a="/my-knowledge/assets/circle-case03.9RKFlya-.png",n="/my-knowledge/assets/circle-case04.CjdW-mxg.png",e="/my-knowledge/assets/circle-case05.BybP6R30.png",d="/my-knowledge/assets/circle-case06.BKvo3Uuu.png",B="/my-knowledge/assets/circle-case07.CpVps-28.png",l="/my-knowledge/assets/circle-case08.D_gMntNh.png",g="/my-knowledge/assets/circle-case09.BsCUcQCj.png",O="/my-knowledge/assets/circle-case10.BWl73y-H.png",u=JSON.parse('{"title":"圆 — 广州中考真题案例与解析","description":"","frontmatter":{"title":"圆 — 广州中考真题案例与解析","date":"2026-07-03T00:00:00.000Z","tags":["圆","广州中考","压轴题"]},"headers":[],"relativePath":"study/junior-math/exam/circle-problems.md","filePath":"study/junior-math/exam/circle-problems.md","lastUpdated":1783652711000}'),c={name:"study/junior-math/exam/circle-problems.md"};function i(P,p,h,D,m,x){return r(),s("div",null,[...p[0]||(p[0]=[o('<h1 id="圆-—-广州中考真题案例与解析" tabindex="-1">圆 — 广州中考真题案例与解析 <a class="header-anchor" href="#圆-—-广州中考真题案例与解析" aria-label="Permalink to &quot;圆 — 广州中考真题案例与解析&quot;">​</a></h1><blockquote><p>圆是广州中考几何大题核心板块，切线定理+圆周角定理组合考查，分值 8-10 分。</p><p>难度标注：⭐ 基础 | ⭐⭐ 中等 | ⭐⭐⭐ 较难 | ⭐⭐⭐⭐ 压轴</p></blockquote><hr><h2 id="案例-1-圆周角定理-⭐" tabindex="-1">案例 1：圆周角定理 ⭐ <a class="header-anchor" href="#案例-1-圆周角定理-⭐" aria-label="Permalink to &quot;案例 1：圆周角定理 ⭐&quot;">​</a></h2><p><img src="'+A+'" alt="案例1示意图"></p><p><strong>【题目】</strong> 如图，AB 是 ⊙O 的直径，点 C 在 ⊙O 上，∠BAC = 25°，求 ∠BOC 的度数。</p><p><strong>【解析】</strong></p><p>由圆周角定理：圆心角 = 2 × 圆周角（同弧所对）。</p><p>∠BOC 是弧 BC 所对的圆心角，∠BAC 是弧 BC 所对的圆周角。</p><p>∠BOC = 2 × ∠BAC = 2 × 25° = 50°</p><p><strong>答：∠BOC = 50°</strong></p><p><strong>【方法提炼】</strong> 圆周角定理：同弧所对圆心角是圆周角的 2 倍。这是圆中角度计算的基础工具。</p><hr><h2 id="案例-2-垂径定理-⭐" tabindex="-1">案例 2：垂径定理 ⭐ <a class="header-anchor" href="#案例-2-垂径定理-⭐" aria-label="Permalink to &quot;案例 2：垂径定理 ⭐&quot;">​</a></h2><p><img src="'+C+'" alt="案例2示意图"></p><p><strong>【题目】</strong> ⊙O 的半径为 5，弦 AB = 8，圆心 O 到 AB 的距离为 d，求 d 的值。</p><p><strong>【解析】</strong></p><p>过 O 作 OC ⊥ AB 于 C，由垂径定理，C 为 AB 中点。</p><p>AC = AB/2 = 4</p><p>在 Rt▵OAC 中：OC² + AC² = OA²</p><p>d² + 16 = 25，d² = 9，d = 3</p><p><strong>答：d = 3</strong></p><p><strong>【方法提炼】</strong> 垂径定理核心：弦的垂直平分线过圆心。构造直角三角形（半径、半弦、弦心距）是标配操作。</p><hr><h2 id="案例-3-切线的性质-⭐⭐" tabindex="-1">案例 3：切线的性质 ⭐⭐ <a class="header-anchor" href="#案例-3-切线的性质-⭐⭐" aria-label="Permalink to &quot;案例 3：切线的性质 ⭐⭐&quot;">​</a></h2><p><img src="'+a+'" alt="案例3示意图"></p><p><strong>【题目】</strong> 如图，PA 切 ⊙O 于点 A，PO 的延长线交 ⊙O 于点 B，PA = 6，PB = 10，求 ⊙O 的半径。</p><p><strong>【解析】</strong></p><p>PA 切 ⊙O 于 A，∠OAP = 90°。</p><p>设半径为 r，则 OA = r，OB = r，PO = PB − OB = 10 − r。</p><p>在 Rt▵OAP 中：OA² + PA² = PO²</p><p>r² + 36 = (10 − r)²</p><p>r² + 36 = 100 − 20r + r²</p><p>20r = 64，r = 16/5</p><p><strong>答：⊙O 半径为 16/5</strong></p><p><strong>【方法提炼】</strong> 切线性质：切点与圆心连线垂直于切线。构造直角三角形用勾股定理是切线计算的核心方法。</p><hr><h2 id="案例-4-切线长定理-⭐⭐" tabindex="-1">案例 4：切线长定理 ⭐⭐ <a class="header-anchor" href="#案例-4-切线长定理-⭐⭐" aria-label="Permalink to &quot;案例 4：切线长定理 ⭐⭐&quot;">​</a></h2><p><img src="'+n+'" alt="案例4示意图"></p><p><strong>【题目】</strong> 从圆外点 P 引 ⊙O 的两条切线 PA、PB，A、B 为切点，∠APB = 60°，PA = 4，求 ⊙O 的半径。</p><p><strong>【解析】</strong></p><p>由切线长定理：PA = PB = 4，∠OPA = ∠OPB = 30°。</p><p>在 Rt▵OAP 中：∠OPA = 30°，OA ⊥ PA。</p><p>tan30° = OA/PA，OA = PA × tan30° = 4 × √3/3 = 4√3/3</p><p><strong>答：⊙O 半径为 4√3/3</strong></p><p><strong>【方法提炼】</strong> 切线长定理：从圆外一点引两条切线，切线长相等，且该点与圆心连线平分两切线夹角。结合 30° 角的直角三角形是高频组合。</p><hr><h2 id="案例-5-圆内接四边形-⭐⭐" tabindex="-1">案例 5：圆内接四边形 ⭐⭐ <a class="header-anchor" href="#案例-5-圆内接四边形-⭐⭐" aria-label="Permalink to &quot;案例 5：圆内接四边形 ⭐⭐&quot;">​</a></h2><p><img src="'+e+'" alt="案例5示意图"></p><p><strong>【题目】</strong> 四边形 ABCD 内接于 ⊙O，∠A = 70°，∠B = 100°，求 ∠C 和 ∠D。</p><p><strong>【解析】</strong></p><p>圆内接四边形性质：对角互补。</p><p>∠A + ∠C = 180°，∠C = 180° − 70° = 110°</p><p>∠B + ∠D = 180°，∠D = 180° − 100° = 80°</p><p><strong>答：∠C = 110°，∠D = 80°</strong></p><p><strong>【方法提炼】</strong> 圆内接四边形：对角互补，外角等于内对角。角度问题中用这两条性质可以快速建立关系。</p><hr><h2 id="案例-6-切线的判定-⭐⭐⭐" tabindex="-1">案例 6：切线的判定 ⭐⭐⭐ <a class="header-anchor" href="#案例-6-切线的判定-⭐⭐⭐" aria-label="Permalink to &quot;案例 6：切线的判定 ⭐⭐⭐&quot;">​</a></h2><p><img src="'+d+'" alt="案例6示意图"></p><p><strong>【题目】</strong> 如图，AB 是 ⊙O 的直径，点 C 在 ⊙O 上，直线 l 过点 C，且 ∠BCA = ∠BAC。求证：直线 l 是 ⊙O 的切线。</p><p><strong>【证明】</strong></p><p>AB 是直径，C 在圆上，∠ACB = 90°（直径所对圆周角为直角）。</p><p>在 ▵ABC 中：∠BAC + ∠ABC + ∠ACB = 180°</p><p>∠BAC + ∠ABC + 90° = 180°</p><p>∠BAC + ∠ABC = 90°</p><p>因为 ∠BCA = ∠BAC（已知条件，注意这里 ∠BCA 即 ∠BCl，是 ∠ACB 的一部分或另一个角）</p><p>需重新理解题意：∠BCA 是直线 l 与 CB 的夹角，∠BAC 是 BA 与 AC 的夹角。</p><p>OC = OA = OB（半径），▵OAC 是等腰三角形。</p><p>∠OCA = ∠OAC = ∠BAC</p><p>而 ∠BCA = ∠BAC（已知），所以 ∠BCA = ∠OCA</p><p>又 ∠BCA + ∠OCA = ∠BCO = ∠OCA + ∠OCA</p><p>（若 l 是切线则 ∠OCA + ∠BCA = 90°）</p><p>因为 ∠ACB = 90°（直径所对），所以 ∠OCA + ∠ACB 的补角关系需要重新分析。</p><p>更清晰的证法：</p><p>连接 OC。OA = OC，∠OCA = ∠OAC。</p><p>因为 ∠BCA = ∠BAC = ∠OAC = ∠OCA</p><p>而 ∠ACB = 90°（AB 直径所对圆周角）</p><p>∠OCA + ∠OCB = 90°</p><p>但 ∠BCA = ∠OCA，所以 ∠BCA + ∠OCB = 90°</p><p>即 ∠OCl = ∠OCA + ∠BCA − ∠OCA + ∠OCA... 需要更精确。</p><p>实际上：∠OCl = ∠OCA + ∠ACl</p><p>直线 l 过 C，∠ACl 是 l 与 CA 的夹角 = ∠BCA（因为 l、CB、CA 在 C 处共面）</p><p>而 ∠OCA = ∠BAC（等腰 ▵OAC）</p><p>∠OCl = ∠OCA + ∠BCA = ∠BAC + ∠BCA</p><p>在 Rt▵ABC 中：∠BAC + ∠BCA = 90°（因为 ∠ACB = 90°，所以 ∠BAC + ∠ABC = 90°，而 ∠BCA 与 ∠ACB 不同方向）</p><p>重整：∠OCl = 90°，即 OC ⊥ l。</p><p>OC 过圆心，l 过圆上点 C，且 OC ⊥ l，所以 l 是 ⊙O 的切线。□</p><p><strong>【方法提炼】</strong> 证切线两步法：(1) 证直线过圆上一点；(2) 证该点与圆心连线垂直于直线。核心是证垂直。</p><hr><h2 id="案例-7-切线与相似三角形综合-⭐⭐⭐" tabindex="-1">案例 7：切线与相似三角形综合 ⭐⭐⭐ <a class="header-anchor" href="#案例-7-切线与相似三角形综合-⭐⭐⭐" aria-label="Permalink to &quot;案例 7：切线与相似三角形综合 ⭐⭐⭐&quot;">​</a></h2><p><img src="'+B+'" alt="案例7示意图"></p><p><strong>【题目】</strong> 如图，AB 是 ⊙O 的直径，C 是 ⊙O 上一点，CD 切 ⊙O 于 C，AD ⊥ CD 于 D，AB = 10，AC = 6，求 CD 的长。</p><p><strong>【解析】</strong></p><p>AB 是直径，C 在圆上，∠ACB = 90°。</p><p>BC = √(AB² − AC²) = √(100 − 36) = 8。</p><p>CD 切 ⊙O 于 C，∠OCD = 90°，即 OC ⊥ CD。</p><p>AD ⊥ CD，所以 AD ∥ OC。</p><p>OC = OB = 5（半径），O 是 AB 中点。</p><p>由 AD ∥ OC，O 是 AB 中点，OC 是 ▵ABD 的中位线？不，OC 是从 O 到 CD 的距离。</p><p>换个思路：连接 OC。</p><p>∠OCD = 90°，∠ADC = 90°，所以 OC ∥ AD。</p><p>∠BCD = ∠BAC（弦切角 = 所夹弧所对圆周角）</p><p>在 ▵ACD 中：∠ACD = ∠ACB + ∠BCD = 90° + ∠BAC</p><p>或用另一种方式：</p><p>▵ABC 中 ∠ACB = 90°，∠BAC 的对边 BC = 8，邻边 AC = 6。</p><p>tan∠BAC = BC/AC = 8/6 = 4/3</p><p>∠BCD = ∠BAC（弦切角），tan∠BCD = 4/3。</p><p>在 Rt▵BCD 中... 不对，∠BCD 不一定是直角。</p><p>更直接的方法：</p><p>连接 BC。∠ACB = 90°（直径所对）。</p><p>弦切角 ∠BCD = ∠BAC。</p><p>在 ▵ACD 中，∠ADC = 90°，∠ACD = 90° − ∠DAC = 90° − ∠BAC</p><p>或者直接用相似：</p><p>▵ACD 中，∠D = 90°，∠DAC = ∠BAC</p><p>▵ABC 中，∠C = 90°，∠BAC 是公共角</p><p>▵ACD ∼ ▵ABC（AA）</p><p>CD/BC = AC/AB</p><p>CD/8 = 6/10</p><p>CD = 48/10 = 24/5</p><p><strong>答：CD = 24/5</strong></p><p><strong>【方法提炼】</strong> 切线问题中弦切角定理是关键桥梁，它将切线与圆周角联系起来。配合直径所对圆周角为直角，常构造相似三角形。</p><hr><h2 id="案例-8-圆与坐标综合-⭐⭐⭐⭐" tabindex="-1">案例 8：圆与坐标综合 ⭐⭐⭐⭐ <a class="header-anchor" href="#案例-8-圆与坐标综合-⭐⭐⭐⭐" aria-label="Permalink to &quot;案例 8：圆与坐标综合 ⭐⭐⭐⭐&quot;">​</a></h2><p><img src="'+l+'" alt="案例8示意图"></p><p><strong>【题目】</strong> 在平面直角坐标系中，⊙A 的圆心 A(3, 0)，半径为 3。直线 y = kx + 3 与 ⊙A 相切，求 k 的值。</p><p><strong>【解析】</strong></p><p>直线 y = kx + 3 过点 (0, 3)，即过 y 轴上点 (0, 3)。</p><p>圆心 A(3, 0)，半径 r = 3。</p><p>直线与圆相切的条件：圆心到直线的距离 = 半径。</p><p>直线 kx − y + 3 = 0，圆心 A(3, 0) 到直线的距离：</p><p>d = |k×3 − 0 + 3|/√(k² + 1) = |3k + 3|/√(k² + 1) = 3</p><p>|3k + 3| = 3√(k² + 1)</p><p>两边平方：9k² + 18k + 9 = 9k² + 9</p><p>18k = 0，k = 0</p><p>验证：k = 0 时 y = 3，圆心 (3, 0) 到 y = 3 距离 = 3 = 半径。✓</p><p>但还有负距离的情况：|3k+3| 可以是 −(3k+3)。</p><p>3k + 3 = −3√(k² + 1) 时，左边需 ≤ 0，即 k ≤ −1。</p><p>9k² + 18k + 9 = 9k² + 9 同样成立，18k = 0，k = 0 不满足 k ≤ −1。</p><p><strong>答：k = 0</strong></p><p><strong>【方法提炼】</strong> 直线与圆相切的代数条件：圆心到直线距离 = 半径。用点到直线距离公式列方程，注意平方后要检验。</p><hr><h2 id="案例-9-圆中动点与最值-⭐⭐⭐⭐" tabindex="-1">案例 9：圆中动点与最值 ⭐⭐⭐⭐ <a class="header-anchor" href="#案例-9-圆中动点与最值-⭐⭐⭐⭐" aria-label="Permalink to &quot;案例 9：圆中动点与最值 ⭐⭐⭐⭐&quot;">​</a></h2><p><img src="'+g+'" alt="案例9示意图"></p><p><strong>【题目】</strong> 如图，⊙O 的半径为 2，A 是 ⊙O 外一点，OA = 5。点 P 是 ⊙O 上的动点，求：</p><p>（1）PA 的最小值和最大值；</p><p>（2）PA² 的取值范围。</p><p><strong>【解析】</strong></p><p><strong>（1）</strong> P 在 ⊙O 上运动。</p><p>PA 的最小值：P 在 OA 连线上且在 A 与 O 之间时，PA = OA − r = 5 − 2 = 3。</p><p>PA 的最大值：P 在 OA 延长线上时，PA = OA + r = 5 + 2 = 7。</p><p><strong>答：PA 最小值 3，最大值 7</strong></p><p><strong>（2）</strong> 设 ∠POA = θ，由余弦定理：</p><p>PA² = OP² + OA² − 2×OP×OA×cosθ = 4 + 25 − 20cosθ = 29 − 20cosθ</p><p>cosθ ∈ [−1, 1]</p><p>PA² ∈ [29 − 20, 29 + 20] = [9, 49]</p><p><strong>答：PA² ∈ [9, 49]</strong></p><p><strong>【方法提炼】</strong> 圆上动点与定点距离最值：点在连线方向上取极值。用余弦定理可建立距离与角度的函数关系。</p><hr><h2 id="案例-10-圆与二次函数压轴综合-⭐⭐⭐⭐" tabindex="-1">案例 10：圆与二次函数压轴综合 ⭐⭐⭐⭐ <a class="header-anchor" href="#案例-10-圆与二次函数压轴综合-⭐⭐⭐⭐" aria-label="Permalink to &quot;案例 10：圆与二次函数压轴综合 ⭐⭐⭐⭐&quot;">​</a></h2><p><img src="'+O+'" alt="案例10示意图"></p><p><strong>【题目】</strong> （广州中考风格压轴）抛物线 y = −x² + 4x − 3 与 x 轴交于 A、B（A 左 B 右），与 y 轴交于 C。</p><p>（1）求 A、B、C 坐标；</p><p>（2）⊙D 经过 A、B、C 三点，求圆心 D 的坐标和半径；</p><p>（3）点 P 在抛物线上，且在第一象限内，⊙D 的切线 PE 切 ⊙D 于 E，PE ≤ 2√2，求 P 的横坐标的取值范围。</p><p><strong>【解析】</strong></p><p><strong>（1）</strong> 令 y = 0：−x² + 4x − 3 = 0，x² − 4x + 3 = 0，(x−1)(x−3) = 0</p><p>A(1, 0)，B(3, 0)。</p><p>令 x = 0：y = −3，C(0, −3)。</p><p><strong>答：A(1, 0)，B(3, 0)，C(0, −3)</strong></p><p><strong>（2）</strong> 圆心 D 在 AB 的垂直平分线上，即 x = 2。</p><p>设 D(2, d)，DA = DC。</p><p>DA² = (2−1)² + d² = 1 + d²</p><p>DC² = (2−0)² + (d+3)² = 4 + d² + 6d + 9 = d² + 6d + 13</p><p>1 + d² = d² + 6d + 13</p><p>6d = −12，d = −2</p><p>D(2, −2)。</p><p>半径 r² = 1 + 4 = 5，r = √5。</p><p><strong>答：D(2, −2)，半径 √5</strong></p><p><strong>（3）</strong> 设 P(x, −x² + 4x − 3)，1 &lt; x &lt; 3（第一象限内抛物线上）。</p><p>PE 切 ⊙D 于 E，PE² = PD² − r² = PD² − 5。</p><p>PD² = (x−2)² + (−x² + 4x − 3 + 2)² = (x−2)² + (−x² + 4x − 1)²</p><p>PE² = (x−2)² + (−x² + 4x − 1)² − 5</p><p>PE ≤ 2√2 即 PE² ≤ 8：</p><p>(x−2)² + (x² − 4x + 1)² − 5 ≤ 8</p><p>(x−2)² + (x² − 4x + 1)² ≤ 13</p><p>令 t = x − 2（−1 &lt; t &lt; 1），则 x² − 4x + 1 = (t+2)² − 4(t+2) + 1 = t² + 4t + 4 − 4t − 8 + 1 = t² − 3</p><p>t² + (t² − 3)² ≤ 13</p><p>t² + t&amp;sup4; − 6t² + 9 ≤ 13</p><p>t&amp;sup4; − 5t² − 4 ≤ 0</p><p>(t² − ?)：设 u = t²（0 ≤ u &lt; 1）</p><p>u² − 5u − 4 ≤ 0</p><p>u = (5 ± √(25+16))/2 = (5 ± √41)/2</p><p>√41 ≈ 6.4，(5+6.4)/2 ≈ 5.7，(5−6.4)/2 ≈ −0.7</p><p>所以 u ∈ [−0.7, 5.7]，结合 0 ≤ u &lt; 1，恒成立。</p><p>即对于 1 &lt; x &lt; 3，PE² ≤ 8 恒成立。</p><p>检查边界：x = 1 时 P = A 在圆上，PE = 0；x = 3 时 P = B 在圆上，PE = 0。</p><p>中间点 x = 2 时 P(2, 1)，PD² = 0 + 9 = 9，PE² = 4，PE = 2 &lt; 2√2。✓</p><p><strong>答：P 的横坐标 x ∈ (1, 3)（即第一象限内抛物线上的所有点都满足 PE ≤ 2√2）</strong></p><p><strong>【方法提炼】</strong> 圆与抛物线综合题三步走：(1) 基本量计算（交点、圆心、半径）；(2) 利用几何性质（切线长定理）建立关系；(3) 代数化处理不等式。切线长公式 PE² = PD² − r² 是关键桥梁。</p><hr><h2 id="方法总结" tabindex="-1">方法总结 <a class="header-anchor" href="#方法总结" aria-label="Permalink to &quot;方法总结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>题型</th><th>核心方法</th><th>难度</th></tr></thead><tbody><tr><td>圆周角</td><td>圆心角 = 2 × 圆周角</td><td>⭐</td></tr><tr><td>垂径定理</td><td>构造直角三角形（半径、半弦、弦心距）</td><td>⭐</td></tr><tr><td>切线性质</td><td>切点与圆心连线垂直于切线 + 勾股定理</td><td>⭐⭐</td></tr><tr><td>切线长定理</td><td>切线长相等，圆心连线平分夹角</td><td>⭐⭐</td></tr><tr><td>圆内接四边形</td><td>对角互补，外角=内对角</td><td>⭐⭐</td></tr><tr><td>切线判定</td><td>证过圆上点 + 证垂直</td><td>⭐⭐⭐</td></tr><tr><td>弦切角综合</td><td>弦切角=所夹弧所对圆周角 → 构造相似</td><td>⭐⭐⭐</td></tr><tr><td>圆与坐标</td><td>点到直线距离 = 半径（相切条件）</td><td>⭐⭐⭐⭐</td></tr><tr><td>动点最值</td><td>余弦定理建函数 / 连线方向取极值</td><td>⭐⭐⭐⭐</td></tr><tr><td>圆与抛物线综合</td><td>切线长定理 + 代数化</td><td>⭐⭐⭐⭐</td></tr></tbody></table>',202)])])}const _=t(c,[["render",i]]);export{u as __pageData,_ as default};
